        {
            // Found a solution
            solutions.Add((int[])queens.Clone()); // Add a copy to avoid modification
            return;
        }

        for (int col = 0; col < n; col++)
        {
            queens[row] = col;
            if (IsSafe(row, col))
            {
                SolveNQueensUtil(row + 1);
            }
        }
    }

    private bool IsSafe(int row, int col)
    {
        for (int i = 0; i < row; i++)
        {
            // Check same column
            if (queens[i] == col)
            {
                return false;
            }

            // Check diagonals
            if (Math.Abs(queens[i] - col) == row - i)
            {
                return false;
            }
        }
        return true;
    }

    public void PrintSolutions()
    {
        foreach (var solution in solutions)
        {
            for (int i = 0; i < n; i++)
            {
                for (int j = 0; j < n; j++)
                {
                    if (solution[i] == j)
                    {
                        Console.Write("Q ");
                    }
                    else
                    {
                        Console.Write(". ");
                    }
                }
                Console.WriteLine();
            }
            Console.WriteLine();
        }
    }

    public static void Main(string[] args)
    {
        int n = 8; // You can change the board size here
        NQueens nQueens = new NQueens(n);
        List<int[]> solutions = nQueens.SolveNQueens();

        Console.WriteLine($"Found {solutions.Count} solutions for {n}-Queens problem:");
        nQueens.PrintSolutions();
    }
}
