```java
// Kode C# kanggo panggonan n Ratu
using System;

class GfG
{
    static void breakLine()
    {
        Console.Write("\n---------------------------------\n");
    }

    // ukuran maksimum papan catur
    static int MAX = 10;

    // array kanggo nyimpen panggonan ratu
    static int[] arr = new int[MAX];

    // variabel kanggo ngetung jumlah solusi sing ditemokake
    static int no;

    // fungsi rekursif kanggo nemokake solusi
    static void nQueens(int k, int n)
    {
        // coba kabeh posisi sing bisa kanggo ratu ing baris saiki
        for (int i = 1; i <= n; i++)
        {
            // priksa yen ratu bisa diselehake ing posisi saiki
            if (canPlace(k, i))
            {
                // selehake ratu ing posisi saiki
                arr[k] = i;

                // yen kabeh ratu diselehake, tampilake solusi
                if (k == n)
                {
                    display(n);
                }
                else
                {
                    // kanthi rekursif coba nyelehake ratu sing isih ana
                    nQueens(k + 1, n);
                }
            }
        }
    }

    // fungsi pembantu kanggo mriksa yen ratu bisa diselehake ing posisi saiki
    static bool canPlace(int k, int i)
    {
        for (int j = 1; j <= k - 1; j++)
        {
            // priksa yen ratu wis diselehake ing kolom utawa diagonal sing padha
            if (arr[j] == i || (Math.Abs(arr[j] - i) == Math.Abs(j - k)))
            {
                return false;
            }
        }
        return true;
    }

    // fungsi kanggo nampilake solusi
    static void display(int n)
    {
        breakLine();
        Console.Write("Tata No. " + ++no);
        breakLine();

        for (int i = 1; i <= n; i++)
        {
            for (int j = 1; j <= n; j++)
            {
                // print '_' kanggo sel kosong lan 'Q' kanggo sel karo ratu
                if (arr[i] != j)
                {
                    Console.Write("\t_");
                }
                else
                {
                    Console.Write("\tQ");
                }
            }
            Console.WriteLine("");
        }

        breakLine();
    }

    // Kode Driver kanggo miwiti masalah lan nelpon fungsi rekursif
    public static void Main(String[] args)
    {
        int n = 4; // ukuran papan catur
        nQueens(1, n);
    }
}
