# Program Python kanggo nyithak super prima sing kurang utawa padha karo n.

# Ngasilake kabeh angka prima sing kurang saka n nggunakake Sieve of Eratosthenes.
def sieve(n):
    is_prime = [True for i in range(n+1)]
    is_prime[0] = False
    is_prime[1] = False

    for p in range(2,n+1):
        if is_prime[p]:
            for i in range(2*p, n+1, p):
                is_prime[i] = False

    return is_prime

def super_primes(n):
    # Ngasilake kabeh angka prima
    is_prime = sieve(n)

    # Nyimpen kabeh angka prima ing array
    primes = [i for i, prime in enumerate(is_prime) if prime]
    primes = [0] + primes
    for i, p in enumerate(primes):
        if is_prime[i]:
            yield p
