Algoritma Dijkstra mehèm banget karo algoritma Prim kanggo wit rentang minimal. Kaya MST Prim, nggawe SPT (wit dalan paling cendhak) kanthi sumber tartamtu minangka oyod. Njaga rong set, siji set ngemot simpul sing kalebu ing wit dalan paling cendhak, set liyane kalebu simpul sing durung kalebu ing wit dalan paling cendhak. Ing saben langkah algoritma, temokake simpul sing ana ing set liyane (set sing durung kalebu) lan nduweni jarak minimal saka sumber.

```c
// Program iki dituju kanggo ngleksanakake algoritma dalan paling cendhak sumber tunggal Dijkstra ing basa C.
// Program kasebut nggunakake matriks adjacency minangka perwakilan saka graf

#include <limits.h>
#include <stdbool.h>
#include <stdio.h>

// Jumlah simpul sing ana ing graf.
#define V 9

// Fungsi sing digunakake kanggo ngenali simpul kanthi nilai jarak paling cilik
// ing antarane sakumpulan simpul sing durung kalebu ing wit dalan paling cendhak.
int findMinDistance(int dist[], bool sptSet[])
{
    // Inisialisasi nilai minimal
    int min = INT_MAX, min_index;

    for (int v = 0; v < V; v++)
        if (sptSet[v] == false && dist[v] <= min)
            min = dist[v], min_index = v;
    return min_index;
}

// Fungsi utilitas kanggo nyetak jarak sing dibangun
// larik
void printSolution(int dist[])
{
    printf("Vertex \t\t Jarak saka Sumber\n");
    for (int i = 0; i < V; i++)
        printf("%d \t\t\t\t %d\n", i, dist[i]);
}

// fungsi sing ngetrapake algoritma Dijkstra kanggo nemokake dalan paling cendhak antarane
// simpul sumber tunggal lan kabeh simpul liyane ing graf. Graf kasebut diwakili nggunakake
// matriks adjacency.
void dijkstra(int graph[V][V], int src)
{
    int dist[V];
    bool processed[V];
    int i, u, v;

    // Inisialisasi kabeh jarak minangka tanpa wates lan diproses minangka salah
    for (i = 0; i < V; i++) {
        dist[i] = INT_MAX;
        processed[i] = false;
    }

    // Jarak simpul sumber saka awake dhewe mesthi 0
    dist[src] = 0;

    // Temokake dalan paling cendhak kanggo kabeh simpul
    for (i = 0; i < V - 1; i++) {
        // Pilih simpul jarak minimal saka sakumpulan simpul sing durung diproses
        u = -1;
        for (i = 0; i < V; i++) {
            if (!processed[i] && (u == -1 || dist[i] < dist[u])) {
                u = i;
            }
        }

        // Tandhani simpul sing dipilih minangka diproses
        processed[u] = true;

        // Nganyari nilai dist saka simpul jejer saka simpul sing dipilih
        for (v = 0; v < V; v++) {
            if (graph[u][v] != 0 && !processed[v]) {
                int new_dist = dist[u] + graph[u][v];
                if (new_dist < dist[v]) {
                    dist[v] = new_dist;
                }
            }
        }
    }

    // Print larik jarak sing dibangun
    printSolution(dist);
}


int main()
{
    /* Gawe graf conto */
    int graph[V][V] = { { 0, 4, 0, 0, 0, 0, 0, 8, 0 },
                        { 4, 0, 8, 0, 0, 0, 0, 11, 0 },
                        { 0, 8, 0, 7, 0, 4, 0, 0, 2 },
                        { 0, 0, 7, 0, 9, 14, 0, 0, 0 },
                        { 0, 0, 0, 9, 0, 10, 0, 0, 0 },
                        { 0, 0, 4, 14, 10, 0, 2, 0, 0 },
                        { 0, 0, 0, 0, 0, 2, 0, 1, 6 },
                        { 8, 11, 0, 0, 0, 0, 1, 0, 7 },
                        { 0, 0, 2, 0, 0, 0, 6, 7, 0 } };

        // Telpon fungsi
        dijkstra(graph, 0);

        return 0;
}
