```java
import java.util.*;

class Solution {

    /**
     * Computes the minimum cost to connect all cities using Prim's algorithm.
     *
     * @param n     The number of cities.
     * @param costs A 2D array where each row represents a connection between two cities
     *              and its cost: {city1, city2, cost}.
     * @return The minimum cost to connect all cities.
     */
    public int minCostConnectPoints(int n, int[][] costs) {
        if (n <= 1) {
            return 0;
        }

        // Build the adjacency list (graph).  Key is the city, value is a list of neighbors
        // and the cost to reach them.
        Map<Integer, List<Pair<Integer, Integer>>> adj = new HashMap<>();
        for (int i = 0; i < n; i++) {
            adj.put(i, new ArrayList<>());
        }

        for (int[] cost : costs) {
            int city1 = cost[0];
            int city2 = cost[1];
            int weight = cost[2];

            adj.get(city1).add(new Pair<>(city2, weight));
            adj.get(city2).add(new Pair<>(city1, weight));
        }

        // Prim's algorithm:

        // Keep track of visited cities.
        boolean[] visited = new boolean[n];

        // Priority queue to store edges with their costs.  Sort by cost (min-heap).
        PriorityQueue<Pair<Integer, Integer>> pq = new PriorityQueue<>(Comparator.comparingInt(Pair::getValue));

        // Start with an arbitrary city (e.g., city 0).
        pq.offer(new Pair<>(0, 0)); // City 0, cost 0
        int minCost = 0; // Total minimum cost.
        int edgesUsed = 0; // Count of edges used.

        while (edgesUsed < n) { //Correct conditional
            Pair<Integer, Integer> current = pq.poll();
            int city = current.getKey();
            int cost = current.getValue();


            if (visited[city]) {
                continue; // Skip already visited cities.
            }

            visited[city] = true;
            minCost += cost;
            edgesUsed++;

            // Add all neighbors of the current city to the priority queue.
            for (Pair<Integer, Integer> neighbor : adj.get(city)) {
                int nextCity = neighbor.getKey();
                int edgeCost = neighbor.getValue();
                if (!visited[nextCity]) {
                    pq.offer(new Pair<>(nextCity, edgeCost));
                }
            }
        }

        return minCost;
    }

    // Helper class to represent a pair of values (city, cost).
    static class Pair<K, V> {
        private final K key;
        private final V value;

        public Pair(K key, V value) {
            this.key = key;
            this.value = value;
        }

        public K getKey() {
            return key;
        }

        public V getValue() {
            return value;
        }
    }


    //Solves LeetCode 1584: Min Cost to Connect All Points
    public int minCostConnectPoints(int[][] points) {
        int n = points.length;
        if (n <= 1) return 0;

        List<int[]> edges = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                int cost = Math.abs(points[i][0] - points[j][0]) + Math.abs(points[i][1] - points[j][1]);
                edges.add(new int[]{i, j, cost});
            }
        }

        // Sort edges by cost
        edges.sort(Comparator.comparingInt(a -> a[2]));

        // Union-Find (Disjoint Set) to detect cycles
        int[] parent = new int[n];
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }

        int minCost = 0;
        int edgesUsed = 0;

        for (int[] edge : edges) {
            int u = edge[0];
            int v = edge[1];
            int cost = edge[2];

            if (find(parent, u) != find(parent, v)) {
                union(parent, u, v);
                minCost += cost;
                edgesUsed++;
                if (edgesUsed == n - 1) break; // Optimization: stop when all points are connected
            }
        }

        return minCost;
    }

    private int find(int[] parent, int i) {
        if (parent[i] == i) return i;
        return parent[i] = find(parent, parent[i]); // Path compression
    }

    private void union(int[] parent, int i, int j) {
        int rootI = find(parent, i);
        int rootJ = find(parent, j);
        parent[rootI] = rootJ;
    }


    public static void main(String[] args) {
        Solution solution = new Solution();

        // Example usage for Prim's algorithm (with adjacency list representation)
        int n1 = 4;
        int[][] costs1 = {{0, 1, 1}, {0, 2, 2}, {1, 2, 5}, {1, 3, 1}, {2, 3, 8}};

        // Convert costs to an adjacency list format compatible with that Prim's algorithm implementation
        Map<Integer, List<Pair<Integer, Integer>>> adj = new HashMap<>();
        for (int i = 0; i < n1; i++) {
            adj.put(i, new ArrayList<>());
        }

        for (int[] cost : costs1) {
            int city1 = cost[0];
            int city2 = cost[1];
            int weight = cost[2];

            adj.get(city1).add(new Pair<>(city2, weight));
            adj.get(city2).add(new Pair<>(city1, weight));
        }

        // Build a costs array compatible with the Prim's implementation
        int costsArray[][] = new int[costs1.length][3];
        for (int i = 0; i < costs1.length; i++){
            costsArray[i][0] = costs1[i][0];
            costsArray[i][1] = costs1[i][1];
            costsArray[i][2] = costs1[i][2];
        }
        int minCost1 = solution.minCostConnectPoints(n1, costsArray);
        System.out.println("Minimum cost (Prim's with adjacency list): " + minCost1);  // Expected output: 4


        //Example usage for LeetCode 1584 problem (Kruskal's Algorithm):
        int[][] points = {{0,0},{2,2},{3,10},{5,2},{7,0}};
        int minCostLeetCode = solution.minCostConnectPoints(points);
        System.out.println("Minimum cost (LeetCode 1584 - Kruskal's): " + minCostLeetCode); // Expected Output: 20

         int[][] points2 = {{3,12},{-2,5},{-4,1}};
        int minCostLeetCode2 = solution.minCostConnectPoints(points2);
        System.out.println("Minimum cost (LeetCode 1584 - Kruskal's): " + minCostLeetCode2); // Expected Output: 18
    }
}
