import java.util.*;

class Solution {

    /**
     * Ngetung biaya minimal kanggo nyambung kabeh kuthe nggunakake algoritma Prim.
     *
     * @param n     Cacahe kutha.
     * @param costs Array 2D ing ngendi saben larik makili sambungan antarane rong kutha
     *              lan biayane: {kutha1, kutha2, biaya}.
     * @return Biaya minimal kanggo nyambung kabeh kutha.
     */
    public int minCostConnectPoints(int n, int[][] costs) {
        if (n <= 1) {
            return 0;
        }

        // Gawe daftar jejer (graf). Kunci yaiku kutha, nilai yaiku dhaptar tangga teparo
        // lan biaya kanggo nggayuh dheweke.
        Map<Integer, List<Pair<Integer, Integer>>> adj = new HashMap<>();
        for (int i = 0; i < n; i++) {
            adj.put(i, new ArrayList<>());
        }

        for (int[] cost : costs) {
            int city1 = cost[0];
            int city2 = cost[1];
            int weight = cost[2];

            adj.get(city1).add(new Pair<>(city2, weight));
            adj.get(city2).add(new Pair<>(city1, weight));
        }

        // Algoritma Prim:

        // Njaga trek kutha sing wis dibukak.
        boolean[] visited = new boolean[n];

        // Antrian prioritas kanggo nyimpen pinggiran kanthi biayane. Urut miturut biaya (tumpukan min).
        PriorityQueue<Pair<Integer, Integer>> pq = new PriorityQueue<>(Comparator.comparingInt(Pair::getValue));

        // Miwiti karo kutha sing sawenang-wenang (contone, kutha 0).
        pq.offer(new Pair<>(0, 0)); // Kutha 0, biaya 0
        int minCost = 0; // Total biaya minimal.
        int edgesUsed = 0; // Cacahing pinggiran sing digunakake.

        while (edgesUsed < n) { //Kondisi sing bener
            Pair<Integer, Integer> current = pq.poll();
            int city = current.getKey();
            int cost = current.getValue();


            if (visited[city]) {
                continue; // Skip kutha sing wis dibukak.
            }

            visited[city] = true;
            minCost += cost;
            edgesUsed++;

            // Tambahake kabeh tangga teparo kutha saiki menyang antrian prioritas.
            for (Pair<Integer, Integer> neighbor : adj.get(city)) {
                int nextCity = neighbor.getKey();
                int edgeCost = neighbor.getValue();
                if (!visited[nextCity]) {
                    pq.offer(new Pair<>(nextCity, edgeCost));
                }
            }
        }

        return minCost;
    }

    // Kelas pembantu kanggo makili pasangan nilai (kutha, biaya).
    static class Pair<K, V> {
        private final K key;
        private final V value;

        public Pair(K key, V value) {
            this.key = key;
            this.value = value;
        }

        public K getKey() {
            return key;
        }

        public V getValue() {
            return value;
        }
    }


    //Ngatasi LeetCode 1584: Biaya Min kanggo Nyambung kabeh Titik
    public int minCostConnectPoints(int[][] points) {
        int n = points.length;
        if (n <= 1) return 0;

        List<int[]> edges = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                int cost = Math.abs(points[i][0] - points[j][0]) + Math.abs(points[i][1] - points[j][1]);
                edges.add(new int[]{i, j, cost});
            }
        }

        // Urut pinggiran miturut biaya
        edges.sort(Comparator.comparingInt(a -> a[2]));

        // Union-Find (Set Disjoint) kanggo ndeteksi siklus
        int[] parent = new int[n];
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }

        int minCost = 0;
        int edgesUsed = 0;

        for (int[] edge : edges) {
            int u = edge[0];
            int v = edge[1];
            int cost = edge[2];

            if (find(parent, u) != find(parent, v)) {
                union(parent, u, v);
                minCost += cost;
                edgesUsed++;
                if (edgesUsed == n - 1) break; // Optimasi: mandheg nalika kabeh titik wis disambungake
            }
        }

        return minCost;
    }

    private int find(int[] parent, int i) {
        if (parent[i] == i) return i;
        return parent[i] = find(parent, parent[i]); // Kompresi jalur
    }

    private void union(int[] parent, int i, int j) {
        int rootI = find(parent, i);
        int rootJ = find(parent, j);
        parent[rootI] = rootJ;
    }


    public static void main(String[] args) {
